+import { Injectable } from '@nestjs/common';
+import { db } from '../database';
+import { transaction } from '../database';
+import { RefundRequest, RefundResult } from './refund.types';
+
+@Injectable()
+export class RefundService {
+  async processRefund(request: RefundRequest): Promise<RefundResult> {
+    return transaction(async (trx) => {
+      const order = await db('orders')
+        .where('id', request.orderId)
+        .transacting(trx)
+        .first();
+
+      if (!order) {
+        throw new Error(`Order ${request.orderId} not found`);
+      }
+
+      if (order.status !== 'completed') {
+        throw new Error(`Order ${request.orderId} is not refundable`);
+      }
+
+      const refund = await db('refunds')
+        .insert({
+          orderId: request.orderId,
+          amount: request.amount ?? order.total,
+          reason: request.reason,
+          status: 'pending',
+        })
+        .transacting(trx)
+        .returning('*');
+
+      await db('orders')
+        .where('id', request.orderId)
+        .update({ status: 'refunded' })
+        .transacting(trx);
+
+      return {
+        refundId: refund[0].id,
+        status: 'pending',
+        amount: refund[0].amount,
+      };
+    });
+  }
+}

