+import { Injectable, Logger } from '@nestjs/common';
+import { PaymentEvent } from '../events/payment-event.types';
+import { WebhookDelivery } from '../events/webhook-delivery';
+import { OrderService } from '../orders/order.service';
+
+@Injectable()
+export class PaymentCapturedHandler {
+  private logger = new Logger(PaymentCapturedHandler.name);
+
+  constructor(
+    private readonly orderService: OrderService,
+    private readonly webhookDelivery: WebhookDelivery,
+  ) {}
+
+  async handle(event: PaymentEvent): Promise<void> {
+    if (event.type !== 'payment.captured') {
+      this.logger.warn(`Unexpected event type: ${event.type}`);
+      return;
+    }
+
+    this.logger.log(`Processing payment.captured for order ${event.orderId}`);
+
+    await this.orderService.markAsPaid(event.orderId, {
+      paymentId: event.paymentId,
+      amount: event.amount,
+      capturedAt: new Date(),
+    });
+
+    await this.webhookDelivery.dispatch({
+      topic: 'order.paid',
+      payload: {
+        orderId: event.orderId,
+        paymentId: event.paymentId,
+        amount: event.amount,
+      },
+    });
+
+    this.logger.log(`Completed payment.captured for order ${event.orderId}`);
+  }
+}

