+import { DatabaseClient } from '../src/database/client';
+import { MigrationLogger } from '../src/database/migration-logger';
+import { UserSchema } from '../src/users/user.schema';
+
+async function main() {
+  const db = new DatabaseClient({
+    host: process.env.DB_HOST ?? 'localhost',
+    port: Number(process.env.DB_PORT ?? 5432),
+    database: process.env.DB_NAME ?? 'app',
+  });
+
+  const logger = new MigrationLogger('migrate-users');
+
+  try {
+    await db.connect();
+    logger.info('Connected to database');
+
+    const users = await db.query('SELECT * FROM users_legacy');
+    logger.info(`Found ${users.length} users to migrate`);
+
+    let migrated = 0;
+    let skipped = 0;
+
+    for (const user of users) {
+      const parsed = UserSchema.safeParse({
+        email: user.email,
+        name: user.full_name,
+        role: user.role ?? 'user',
+        createdAt: user.created_at,
+      });
+
+      if (!parsed.success) {
+        logger.warn(`Skipping user ${user.id}: ${parsed.error.message}`);
+        skipped++;
+        continue;
+      }
+
+      await db.query('INSERT INTO users (email, name, role, created_at) VALUES ($1, $2, $3, $4)', [
+        parsed.data.email, parsed.data.name, parsed.data.role, parsed.data.createdAt,
+      ]);
+      migrated++;
+    }
+
+    logger.info(`Migration complete: ${migrated} migrated, ${skipped} skipped`);
+  } finally {
+    await db.disconnect();
+  }
+}
+
+main().catch(console.error);

