+import { Controller, Get, Query } from '@nestjs/common';
+import { MetricsQuery, MetricsResponse } from './metrics.types';
+import { AnalyticsService } from './analytics.service';
+
+@Controller('metrics')
+export class MetricsController {
+  constructor(private readonly analyticsService: AnalyticsService) {}
+
+  @Get()
+  async getMetrics(@Query() query: MetricsQuery): Promise<MetricsResponse> {
+    const startDate = query.startDate
+      ? new Date(query.startDate)
+      : new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);
+    const endDate = query.endDate
+      ? new Date(query.endDate)
+      : new Date();
+
+    const result = await this.analyticsService.query({
+      metrics: query.metrics ?? ['pageViews', 'uniqueVisitors'],
+      startDate,
+      endDate,
+      granularity: query.granularity ?? 'day',
+      filters: query.filters,
+    });
+
+    return {
+      data: result.data,
+      metadata: {
+        queriedAt: new Date().toISOString(),
+        granularity: query.granularity ?? 'day',
+      },
+    };
+  }
+}
